import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Ensure user input does not exceed buffer size
        char[] buffer = new char[Math.min(userInput.length(), 10)];

        // Safely copy user input to buffer
        for (int i = 0; i < buffer.length; i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
